module top_module(
    input [3:0] data_in,
    input load, shift, reset, clk,
    output [3:0] data_out
);reg [3:0] clear_reg;

always @(posedge clk) begin
    if (reset) begin
        clear_reg <= 4'b0000;
    end else if (load) begin
        clear_reg <= data_in;
    end else if (shift) begin
        clear_reg <= {clear_reg[2:0], 1'b0};
    end
end

assign data_out = clear_reg;

endmodule
